INSERT INTO products (id, sku, title_it, title_en, category_id, price, stock_quantity, box_quantity, description_it, description_en, image_urls, is_accessory, attributes, created_at, is_active, price_tiers) VALUES ('5177842d-1978-465a-97a0-a7f3c0163389', 'ZL415.0002', 'Lisbona', NULL, NULL, 0.85, 27930, 1000, '<p>Il contagocce Lisbona&nbsp;&egrave; stato appositamente progettato per essere abbinato al flacone Sydney&nbsp;30 ml, seguendone&nbsp;linee e proporzioni, per conferire il massimo equilibrio estetico. Ideale per l&rsquo;erogazione di un&rsquo;ampia gamma di prodotti cosmetici, di make-up e per la cura dei capelli.</p>', '<p>The dropper Lisbona has been designed for the&nbsp;<a href="http://www.vetronaviglio.it/en/glass-packaging/products/3/glass-bottles/346/sydney">Sydney</a>&nbsp;30 ml bottle; its form and proportions have&nbsp;been specifically designed for the best aesthetic result. It is ideal solution for dispensing of a variety of skincare, make-up&nbsp;and haircare products.</p>', '["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/ZL415.0002.jpg"]', TRUE, '{"ml": 0, "colore": "Ghiera bianco lucido, bulbo bianco", "finitura": "Nessuna finitura", "categoria": "Contagocce", "materiale": "PP", "imboccatura": "GCMI 18/415"}', '2026-06-16T09:25:33.672564+00:00', TRUE, '[]');
